<!DOCTYPE html><html><head><meta charset='utf-8'><title>Alerts</title><link rel='stylesheet' href='automation_playground.css'></head><body><div class='container'><a href='/index.php'>Home</a><h2>Alerts</h2><div class='panel'><button id='alerts-show-alert' class='btn'>Show Alert</button> <button id='alerts-show-confirm' class='btn'>Show Confirm</button><div id='alerts-result' class='result'>READY</div></div></div><script>document.getElementById('alerts-show-alert').onclick=()=>{alert('ALERT_MESSAGE_STATIC');document.getElementById('alerts-result').textContent='ALERT_SHOWN'};document.getElementById('alerts-show-confirm').onclick=()=>{const ok=confirm('CONFIRM_MESSAGE_STATIC');document.getElementById('alerts-result').textContent=ok?'CONFIRM_ACCEPTED':'CONFIRM_DISMISSED'};</script></body></html>
